"""Agent Management API endpoints."""

from typing import Any, Dict, List, Optional
from fastapi import APIRouter, Depends, HTTPException, Request
from pydantic import BaseModel, Field

from src.core.agent_service import AgentService
from src.infra.db.arango_client import get_arango_manager
from src.errors.exceptions import AgentNotFoundError, ValidationError

router = APIRouter()


class AgentCapability(BaseModel):
    """Agent capability definition - matches monolith schema."""
    name: str
    description: str
    input_schema: Dict[str, Any]
    output_schema: Dict[str, Any]


class CreateAgentRequest(BaseModel):
    """Create agent request - matches monolith AgentConfiguration schema."""
    # Note: Validation is done manually in the endpoint to match monolith behavior (returns 400 not 422)
    name: str = Field(..., description="Agent name")
    description: str = Field(..., description="Agent description")
    agent_type: str = Field(..., description="llm, tool_based, hybrid")
    capabilities: List[AgentCapability] = Field(..., description="Agent capabilities")
    max_concurrent_tasks: int = Field(default=5, ge=1, le=100)
    timeout_seconds: int = Field(default=300, ge=10, le=3600)
    resource_allocation: Dict[str, Any] = Field(default_factory=dict)
    integration_settings: Dict[str, Any] = Field(default_factory=dict)


class UpdateAgentRequest(BaseModel):
    name: Optional[str] = None
    description: Optional[str] = None
    configuration: Optional[Dict[str, Any]] = None
    system_prompt: Optional[str] = None


class ManagerAssignment(BaseModel):
    manager_id: str
    manager_name: str
    manager_email: str


def get_agent_service() -> AgentService:
    """Dependency to get AgentService with ArangoDB."""
    arango = get_arango_manager()
    return AgentService(arango)


@router.post("/create")
async def create_agent(
    data: CreateAgentRequest,
    service: AgentService = Depends(get_agent_service),
):
    """Create a new AI agent (monolith-compatible route at /agents/create)."""
    # Validate name length - matches monolith validation (returns 400 not 422)
    if not data.name or len(data.name) < 3:
        raise HTTPException(status_code=400, detail="Agent name must be at least 3 characters")

    # Validate agent_type - matches monolith validation
    if data.agent_type not in ("llm", "tool_based", "hybrid"):
        raise HTTPException(status_code=400, detail="Agent type must be 'llm', 'tool_based', or 'hybrid'")

    # Validate capabilities - matches monolith validation
    if not data.capabilities:
        raise HTTPException(status_code=400, detail="Agent must have at least one capability")

    try:
        # Format data to match monolith structure
        agent_data = {
            "name": data.name,
            "description": data.description,
            "type": data.agent_type,
            "agent_type": data.agent_type,
            "capabilities": [cap.model_dump() for cap in data.capabilities],
            "configuration": {
                "max_concurrent_tasks": data.max_concurrent_tasks,
                "timeout_seconds": data.timeout_seconds,
                "resource_allocation": data.resource_allocation,
                "integration_settings": data.integration_settings,
            },
        }
        agent = await service.create_agent(agent_data)
        return {"agent_id": agent["id"], "status": "created", "message": f"Agent '{agent['name']}' created successfully"}
    except ValidationError as e:
        raise HTTPException(status_code=400, detail=e.message)


@router.get("")
async def list_agents(
    service: AgentService = Depends(get_agent_service),
):
    """List all agents with current performance metrics.

    Note: Query parameters (status, tenant_id) are intentionally not supported
    to match the monolith backend behavior which ignores these parameters.
    """
    agents = await service.list_agents()

    # Get current performance metrics for each agent (calculated from agent_tasks)
    # This matches the behavior of the monolith backend
    for agent in agents:
        metrics = await service.get_agent_metrics(agent['id'])
        agent["metrics"] = metrics

    return agents


@router.get("/{agent_id}")
async def get_agent(
    agent_id: str,
    service: AgentService = Depends(get_agent_service),
):
    """Get agent by ID."""
    try:
        agent = await service.get_agent(agent_id)
        metrics = await service.get_agent_metrics(agent_id)
        agent["metrics"] = metrics
        return agent
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.put("/{agent_id}")
async def update_agent(
    agent_id: str,
    data: UpdateAgentRequest,
    service: AgentService = Depends(get_agent_service),
):
    """Update agent configuration (partial update)."""
    try:
        agent = await service.update_agent(agent_id, data.model_dump(exclude_none=True))
        # Match monolith response format
        return {
            "agent_id": agent["id"],
            "status": "updated",
            "message": "Agent configuration updated successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.put("/{agent_id}/configuration")
async def update_agent_configuration(
    agent_id: str,
    config: CreateAgentRequest,
    service: AgentService = Depends(get_agent_service),
):
    """Update agent configuration (full update - monolith-compatible route)."""
    try:
        # Format data to match monolith structure
        update_data = {
            "name": config.name,
            "description": config.description,
            "type": config.agent_type,
            "agent_type": config.agent_type,
            "capabilities": [cap.model_dump() for cap in config.capabilities],
            "configuration": {
                "max_concurrent_tasks": config.max_concurrent_tasks,
                "timeout_seconds": config.timeout_seconds,
                "resource_allocation": config.resource_allocation,
                "integration_settings": config.integration_settings,
            },
        }
        agent = await service.update_agent(agent_id, update_data)
        # Match monolith response format
        return {
            "agent_id": agent["id"],
            "status": "updated",
            "message": "Agent configuration updated successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.delete("/{agent_id}")
async def delete_agent(
    agent_id: str,
    service: AgentService = Depends(get_agent_service),
):
    """Delete an agent."""
    try:
        result = await service.delete_agent(agent_id)
        # Match monolith response format
        return {
            "agent_id": agent_id,
            "status": "deleted",
            "removed_tasks": result.get("removed_tasks", 0) if isinstance(result, dict) else 0,
            "message": "Agent deleted successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.post("/{agent_id}/start")
async def start_agent(
    agent_id: str,
    service: AgentService = Depends(get_agent_service),
):
    """Start an agent."""
    try:
        await service.update_agent(agent_id, {"status": "active"})
        # Match monolith response format
        return {
            "agent_id": agent_id,
            "status": "active",
            "message": "Agent started successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.post("/{agent_id}/stop")
async def stop_agent(
    agent_id: str,
    service: AgentService = Depends(get_agent_service),
):
    """Stop an agent."""
    try:
        agent = await service.stop_agent(agent_id)
        # Match monolith response format
        return {
            "agent_id": agent["id"],
            "status": agent["status"],
            "cancelled_tasks": 0,
            "message": "Agent stopped successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.get("/{agent_id}/performance")
async def get_agent_performance(
    agent_id: str,
    service: AgentService = Depends(get_agent_service),
):
    """Get agent performance metrics."""
    try:
        await service.get_agent(agent_id)
        metrics = await service.get_agent_metrics(agent_id)
        return {"agent_id": agent_id, **metrics}
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.post("/{agent_id}/assign-manager")
async def assign_manager(
    agent_id: str,
    manager: ManagerAssignment,
    service: AgentService = Depends(get_agent_service),
):
    """Assign a manager to an agent."""
    try:
        await service.update_agent(agent_id, {
            "assigned_manager_id": manager.manager_id,
            "assigned_manager_name": manager.manager_name,
            "assigned_manager_email": manager.manager_email,
        })
        # Match monolith response format
        return {
            "agent_id": agent_id,
            "manager": manager.model_dump(),
            "status": "assigned",
            "message": f"Manager {manager.manager_name} assigned successfully"
        }
    except AgentNotFoundError:
        raise HTTPException(status_code=404, detail="Agent not found")


@router.get("/statistics/overview")
async def get_agents_overview(
    service: AgentService = Depends(get_agent_service),
):
    """Get overview statistics for all agents."""
    # Return statistics directly from database - matches monolith format
    stats = service.get_statistics()
    return stats

